      // 13：”26.90″，“买二”
      // 14：”14700″，“买三”
      // 15：”26.89″，“买三”
      // 16：”14300″，“买四”
      // 17：”26.88″，“买四”
      // 18：”15100″，“买五”
      // 19：”26.87″，“买五”
